-- Retrieve Table of Contents of a container file.
local function retrieve_toc(base_address)

	local table_name = {}
	local n = readBytes(base_address, 1)

	for i = 1, n do

		table_name[#table_name + 1] = base_address + (readInteger(base_address + (i * 4)))

	end

	return table_name
end

-- Check current version and amount of active instances of PCSX2, set working RAM region.
local function pcsx2_version_check()

	version_id = nil
	pcsx2_id_ram_start = nil
	error_flag = nil
	local process_found = {}

	for processID, processName in pairs(getProcessList()) do

		if processName == "pcsx2.exe" or processName == "pcsx2-qt.exe" then

			process_found[#process_found + 1] = processName
			process_found[#process_found + 1] = processID

		end

	end

	if process_found[1] ~= nil then -- Check if there's an instance of PCSX2 up.

		if #process_found <= 2 then -- If CE is using AutoAttach then check how many instances of PCSX2 are up.

			if (process_found[2] == getOpenedProcessID()) then -- Check if CE is attached to PCSX2.

				-- Set memory region according to the version of the emulator.
				-- Check if there's a game loaded, too.
				if process_found[1] == "pcsx2.exe" then

					version_id = 1
					pcsx2_id_ram_start = getAddress(0x20000000)

					if readInteger(pcsx2_id_ram_start) == nil then

						error_flag = 3

					end

				elseif process_found[1] == "pcsx2-qt.exe" then

					version_id = 2
					pcsx2_id_ram_start = getAddress(readPointer("pcsx2-qt.EEmem"))

					if readInteger(pcsx2_id_ram_start) == 0 then

						error_flag = 3

					end

				end

			else

				error_flag = 1

			end

		else

			error_flag = 2

		end

	else

		error_flag = 1

	end

	return {version_id, pcsx2_id_ram_start, error_flag}

end

-- Memory scanner function
local function memscan_func(scanoption, vartype, roundingtype, input1, input2, startAddress, stopAddress, protectionflags, alignmenttype, alignmentparam, isHexadecimalInput, isNotABinaryString, isunicodescan, iscasesensitive)

	local memory_scan = createMemScan()
	memory_scan.firstScan(scanoption, vartype, roundingtype, input1, input2 ,startAddress ,stopAddress ,protectionflags ,alignmenttype, alignmentparam, isHexadecimalInput, isNotABinaryString, isunicodescan, iscasesensitive)
	memory_scan.waitTillDone()
	local found_list = createFoundList(memory_scan)
	found_list.initialize()
	local address_list = {}

	if (found_list ~= nil) then

		for i = 0, found_list.count - 1 do

			table.insert(address_list, getAddress(found_list[i]))

		end

	end

	found_list.deinitialize()
	found_list.destroy()
	found_list = nil

	return address_list

end

-- "X item exists in Y table" check function
local function value_exists(tab, val)

	for index, value in ipairs(tab) do

		if value == val then

			return true

		end

	end

	return false

end

-- Extended modifications function.
function ACZenvCustom_outSortieCheck(ACZenvCustom_outSortieCheckTimer)

	--Run function and script as long PCSX2 is up
	if readInteger(EERAMver_ACZenvCustom[2]) ~= nil then

		-- Check if the player is not in muultiplayer mode.
		if readBytes(EERAMver_ACZenvCustom[2] + 0x3ACEA0, 1) == 13 then

			-- Check if the mission is already playing.
			if (readBytes(EERAMver_ACZenvCustom[2] + 0x3FFD1C, 1) == 3) then

				-- Pause emulator.
				pause(getOpenedProcessID())

				-- Scan for file the stage's assets file address.
				local found_list = memscan_func(soExactValue, vtByteArray, nil, "27 00 00 00 A0 00 00 00 A0 01 00 00", nil, EERAMver_ACZenvCustom[2] + 0x700000, EERAMver_ACZenvCustom[2] + 0x1F00000, "", 2, "0", true, nil, nil, nil)

				-- Pause "out-of-sortie" checker function.
				ACZenvCustom_outSortieCheckTimer.enabled = false

				-- Clear table for reuse.
				for k, v in pairs(ACZenvCustom_dataList) do ACZenvCustom_dataList[k] = nil end

				-- Get current stage's ID.
				local stage_id = readSmallInteger(EERAMver_ACZenvCustom[2] + 0x3BF740) -- Read the current mission ID value.

				-- Get stage file ToC.
				local stage_dat_file_toc = retrieve_toc(found_list[1])

				-- Read and store address and bytearray data of the first stage environment set.
				ACZenvCustom_dataList[#ACZenvCustom_dataList + 1] = stage_dat_file_toc[19] -- Environment configuration file address
				ACZenvCustom_dataList[#ACZenvCustom_dataList + 1] = readBytes(stage_dat_file_toc[19], 864, true) -- Environment configuration file as bytearray data

				-- Read and store address and bytearray data of the second stage environment set.
				ACZenvCustom_dataList[#ACZenvCustom_dataList + 1] = stage_dat_file_toc[38]
				ACZenvCustom_dataList[#ACZenvCustom_dataList + 1] = readBytes(stage_dat_file_toc[38], 864, true)

				-- If the main stage file has a take-off/landing/refueling stage in it then also append its start offsets and environment data.
				if readBytes(stage_dat_file_toc[39], 1) == 38 then

					-- Set and address pointer and a table to retrieve the sub-stage environment data.
					local sub_stage_dat_file_toc = retrieve_toc(stage_dat_file_toc[39])

					-- Read and store address and bytearray data of the first sub-stage environment set.
					ACZenvCustom_dataList[#ACZenvCustom_dataList + 1] = sub_stage_dat_file_toc[19]
					ACZenvCustom_dataList[#ACZenvCustom_dataList + 1] = readBytes(sub_stage_dat_file_toc[19], 864, true)

					-- Read and store address and bytearray data of the second sub-stage environment set.
					ACZenvCustom_dataList[#ACZenvCustom_dataList + 1] = sub_stage_dat_file_toc[38]
					ACZenvCustom_dataList[#ACZenvCustom_dataList + 1] = readBytes(sub_stage_dat_file_toc[38], 864, true)

				end

				-- //[ENVIRONMENT MODIFIERS]// --
				-- Apply the modifications to all environment parameter sets found.
				-- Assign bytearray to the "STAGE_ENV_PARAM_LIST" variable according to the current "STAGE_ID" value.

