		-- Do the same with the "[ACZGCT] Force maximum LoD for NPC objects during a mission" cheat.
		if readInteger(EERAMver_ACZenvCustom[2] + 0x3F7800) ~= 1040187392 then

			showMessage("<< You might want to enable the [[ACZGCT] Force maximum LoD for NPC objects during a mission] cheat. >>")

